    dangerous_patterns = [
        r'subprocess\.call\(\s*["\']rm["\'][^,]',
        r'exec\(\s*input\(\s*',
        r'os\.system\(\s*["\']del["\'][^,]',
        r'__import__\(\s*["\']os["\']\)'
