from ag2 import GroupChat
from collections import deque, Counter

class FairGroupChat(GroupChat):
    def __init__(self, agents, max_rounds_per_agent=3):
        super().__init__(agents)
        self.speaker_queue = deque(agents)
        self.round_counts = Counter()
        self.max_rounds = max_rounds_per_agent

    def select_speaker(self):
        while self.speaker_queue:
            candidate = self.speaker_queue[0]
            if self.round_counts[candidate.name] < self.max_rounds:
                self.speaker_queue.rotate(-1)
                return candidate
            else:
                self.speaker_queue.rotate(-1)
        return super().select_speaker()

from ag2 import AssistantAgent
from sentence_transformers import SentenceTransformer

class TopicGuardian(AssistantAgent):
    def __init__(self, task_prompt, drift_threshold=0.7):
        super().__init__()
        self.model = SentenceTransformer('all-MiniLM-L6-v2')
        self.task_prompt = task_prompt
        self.drift_threshold = drift_threshold
        self.last_check = 0

    def generate_reply(self, messages, sender):
        if len(messages) - self.last_check > 10:
            task_emb = self.model.encode(self.task_prompt)
            conv_emb = self.model.encode(' '.join([m['content'] for m in messages[-5:]]))
            similarity = np.dot(task_emb, conv_emb) / (np.linalg.norm(task_emb) * np.linalg.norm(conv_emb))

            if similarity < self.drift_threshold:
                self.last_check = len(messages)
                return f"[TOPIC REFOCUS] Returning to main task: {self.task_prompt}"
        return super().generate_reply(messages, sender)
